/**
 * ==========================================================
 * КАК РАБОТАТЬ С ЭТИМ КОДОМ (простыми словами)
 * ==========================================================
 * 1) Ты задаешь 2 переменные сверху:
 *    - WORKFLOW: текущий ComfyUI workflow JSON (объект или строка JSON)
 *    - ACTIONS: список действий (массив или строка JSON)
 *
 * 2) Код применяет ACTIONS по порядку и возвращает обновленный workflow.
 *
 * 3) Что можно делать через ACTIONS:
 *    - addNode      -> добавить ноду
 *    - connect      -> добавить связь
 *    - disconnect   -> удалить связь
 *    - removeNode   -> удалить ноду (и все входящие ссылки на нее)
 *
 * 4) Важно:
 *    - Для ComfyUI id лучше числовые ("115", "116"...)
 *    - Порядок ACTIONS имеет значение (действия выполняются сверху вниз)
 *    - Можно добавлять сразу много нод за один запуск
 *
 * ----------------------------------------------------------
 * Пример ACTIONS:
 * [
 *   {
 *     "type": "addNode",
 *     "ref": "lora1",
 *     "node": {
 *       "class_type": "LoraLoaderModelOnly",
 *       "_meta": { "title": "Load LoRA" },
 *       "inputs": { "lora_name": "geminicomics_style.safetensors", "strength_model": 1 }
 *     },
 *     "connectInputs": { "model": ["122", 0] }
 *   },
 *   {
 *     "type": "connect",
 *     "fromRef": "lora1",
 *     "fromOutput": 0,
 *     "toNodeId": "130",
 *     "toInput": "model"
 *   }
 * ]
 *
 * Где можно использовать ссылку на только что добавленную ноду:
 * - "ref": "lora1" в addNode
 * - потом "fromRef": "lora1" или "toRef": "lora1"
 * ==========================================================
 */

// -------------------- ТВОИ ПЕРЕМЕННЫЕ --------------------
// Подставь имена своих нод n8n:
const WORKFLOW = $('Start').first().json.workflow;
const ACTIONS = $('Start').first().json.actions;

// false = разрешены только numeric id (рекомендовано для ComfyUI)
const ALLOW_NON_NUMERIC_IDS = false;
// ---------------------------------------------------------

function isObj(v) {
  return v !== null && typeof v === 'object' && !Array.isArray(v);
}

function clone(v) {
  return JSON.parse(JSON.stringify(v));
}

function parseJsonMaybe(value, name) {
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch (e) {
      throw new Error(`${name}: invalid JSON string. ${e.message}`);
    }
  }
  if (isObj(value) || Array.isArray(value)) return clone(value);
  throw new Error(`${name} must be object/array or JSON string`);
}

function validateId(id) {
  if (ALLOW_NON_NUMERIC_IDS) return;
  if (!/^\d+$/.test(String(id))) {
    throw new Error(`Invalid node id "${id}". Use numeric ids for ComfyUI.`);
  }
}

function makeIdAllocator(nodesMap) {
  const used = new Set(Object.keys(nodesMap).map(String));
  let maxNum = 0;

  for (const k of used) {
    if (/^\d+$/.test(k)) maxNum = Math.max(maxNum, Number(k));
  }

  return {
    reserve(id) {
      if (used.has(id)) return false;
      used.add(id);
      if (/^\d+$/.test(id)) maxNum = Math.max(maxNum, Number(id));
      return true;
    },
    alloc() {
      let n = maxNum + 1;
      while (used.has(String(n))) n++;
      const id = String(n);
      used.add(id);
      maxNum = n;
      return id;
    },
  };
}

// -------- Parse workflow --------
const workflowRoot = parseJsonMaybe(WORKFLOW, 'WORKFLOW');
const hasPromptWrapper = isObj(workflowRoot.prompt);
const nodes = clone(hasPromptWrapper ? workflowRoot.prompt : workflowRoot);

if (!isObj(nodes)) {
  throw new Error('WORKFLOW must be a ComfyUI prompt object (nodeId -> nodeData)');
}

// -------- Parse actions --------
const parsedActions = parseJsonMaybe(ACTIONS, 'ACTIONS');
const actions = Array.isArray(parsedActions)
  ? parsedActions
  : (isObj(parsedActions) && Array.isArray(parsedActions.actions) ? parsedActions.actions : null);

if (!Array.isArray(actions)) {
  throw new Error('ACTIONS must be array or object with actions[]');
}

const idMap = {}; // ref -> real node id
const allocator = makeIdAllocator(nodes);

function hasNode(id) {
  return Object.prototype.hasOwnProperty.call(nodes, String(id));
}

function ensureInputs(nodeId) {
  if (!isObj(nodes[nodeId].inputs)) nodes[nodeId].inputs = {};
}

function assertNodeExists(id, where = '') {
  if (!hasNode(id)) {
    throw new Error(`Node ${id} not found${where ? ` (${where})` : ''}`);
  }
}

function parseExplicitId(raw, fieldName) {
  if (raw === undefined || raw === null) {
    throw new Error(`${fieldName} is required`);
  }
  if (typeof raw === 'number') {
    const id = String(raw);
    validateId(id);
    return id;
  }
  if (typeof raw === 'string') {
    if (raw.startsWith('@')) {
      throw new Error(`${fieldName} cannot be a ref (@...)`);
    }
    validateId(raw);
    return raw;
  }
  throw new Error(`${fieldName} must be string or number`);
}

function resolveNodeId(raw, fieldName) {
  if (raw === undefined || raw === null) {
    throw new Error(`${fieldName} is required`);
  }

  if (typeof raw === 'number') {
    const id = String(raw);
    validateId(id);
    return id;
  }

  if (typeof raw === 'string') {
    if (raw.startsWith('@')) {
      const ref = raw.slice(1);
      if (!idMap[ref]) throw new Error(`Unknown ref "${ref}"`);
      return idMap[ref];
    }
    validateId(raw);
    return raw;
  }

  if (isObj(raw)) {
    if (raw.ref) return resolveNodeId(`@${raw.ref}`, fieldName);
    if (raw.id !== undefined) return resolveNodeId(raw.id, fieldName);
    if (raw.nodeId !== undefined) return resolveNodeId(raw.nodeId, fieldName);
  }

  throw new Error(`Invalid ${fieldName}: ${JSON.stringify(raw)}`);
}

function resolveLinkSource(src, fieldName) {
  if (Array.isArray(src)) {
    const fromId = resolveNodeId(src[0], `${fieldName}[0]`);
    const out = Number(src[1] ?? 0);
    if (!Number.isInteger(out) || out < 0) {
      throw new Error(`Invalid output index in ${fieldName}`);
    }
    return [fromId, out];
  }

  if (typeof src === 'string' || typeof src === 'number') {
    const fromId = resolveNodeId(src, fieldName);
    return [fromId, 0];
  }

  if (isObj(src)) {
    const fromRaw = src.nodeId ?? src.id ?? (src.ref ? `@${src.ref}` : undefined);
    const fromId = resolveNodeId(fromRaw, `${fieldName}.nodeId`);
    const out = Number(src.output ?? src.fromOutput ?? 0);
    if (!Number.isInteger(out) || out < 0) {
      throw new Error(`Invalid output index in ${fieldName}`);
    }
    return [fromId, out];
  }

  throw new Error(`Invalid ${fieldName}`);
}

// Pre-pass для addNode: заранее выдаем id и ref,
// чтобы можно было ссылаться через @ref.
for (let i = 0; i < actions.length; i++) {
  const a = actions[i];
  if (!isObj(a)) throw new Error(`actions[${i}] must be object`);
  if (a.type !== 'addNode') continue;

  let assignedId;
  if (a.id !== undefined) {
    assignedId = parseExplicitId(a.id, `actions[${i}].id`);

    if (!hasNode(assignedId)) {
      const reserved = allocator.reserve(assignedId);
      if (!reserved) {
        throw new Error(`actions[${i}]: id ${assignedId} already reserved`);
      }
    }
  } else {
    assignedId = allocator.alloc();
  }

  a.__assignedId = assignedId;

  if (a.ref) {
    if (idMap[a.ref] && idMap[a.ref] !== assignedId) {
      throw new Error(`actions[${i}]: ref "${a.ref}" mapped to multiple ids`);
    }
    idMap[a.ref] = assignedId;
  }
}

function connect(action) {
  const fromRaw = action.fromNodeId ?? action.from ?? (action.fromRef ? `@${action.fromRef}` : undefined);
  const toRaw = action.toNodeId ?? action.to ?? (action.toRef ? `@${action.toRef}` : undefined);
  const toInput = action.toInput ?? action.input;

  const fromId = resolveNodeId(fromRaw, 'connect.fromNodeId');
  const toId = resolveNodeId(toRaw, 'connect.toNodeId');

  if (!toInput) throw new Error('connect.toInput is required');

  assertNodeExists(fromId, 'connect.fromNodeId');
  assertNodeExists(toId, 'connect.toNodeId');

  const out = Number(action.fromOutput ?? action.output ?? 0);
  if (!Number.isInteger(out) || out < 0) {
    throw new Error('connect.fromOutput must be integer >= 0');
  }

  ensureInputs(toId);
  nodes[toId].inputs[toInput] = [fromId, out];
}

function disconnect(action) {
  const toRaw = action.toNodeId ?? action.to ?? (action.toRef ? `@${action.toRef}` : undefined);
  const fromRaw = action.fromNodeId ?? action.from ?? (action.fromRef ? `@${action.fromRef}` : undefined);
  const toInput = action.toInput ?? action.input;

  const hasTo = toRaw !== undefined;
  const hasFrom = fromRaw !== undefined;

  const fromId = hasFrom ? resolveNodeId(fromRaw, 'disconnect.fromNodeId') : null;
  const outRaw = action.fromOutput ?? action.output;
  const out = outRaw === undefined ? null : Number(outRaw);

  const match = (v) => {
    if (!Array.isArray(v) || v.length < 2) return false;
    if (fromId !== null && String(v[0]) !== String(fromId)) return false;
    if (out !== null && Number(v[1]) !== out) return false;
    return true;
  };

  if (hasTo) {
    const toId = resolveNodeId(toRaw, 'disconnect.toNodeId');
    assertNodeExists(toId, 'disconnect.toNodeId');
    if (!isObj(nodes[toId].inputs)) return;

    if (toInput) {
      const cur = nodes[toId].inputs[toInput];
      if (cur !== undefined && (!hasFrom || match(cur))) {
        delete nodes[toId].inputs[toInput];
      }
      return;
    }

    for (const [k, v] of Object.entries(nodes[toId].inputs)) {
      if (!hasFrom || match(v)) delete nodes[toId].inputs[k];
    }
    return;
  }

  if (hasFrom) {
    for (const node of Object.values(nodes)) {
      if (!isObj(node.inputs)) continue;
      for (const [k, v] of Object.entries(node.inputs)) {
        if (!match(v)) continue;
        if (toInput && k !== toInput) continue;
        delete node.inputs[k];
      }
    }
    return;
  }

  throw new Error('disconnect: provide toNodeId or fromNodeId');
}

function removeNode(action) {
  const raw = action.nodeId ?? action.id ?? (action.ref ? `@${action.ref}` : undefined);
  const id = resolveNodeId(raw, 'removeNode.nodeId');

  if (!hasNode(id)) return;

  for (const node of Object.values(nodes)) {
    if (!isObj(node.inputs)) continue;
    for (const [k, v] of Object.entries(node.inputs)) {
      if (Array.isArray(v) && String(v[0]) === String(id)) {
        delete node.inputs[k];
      }
    }
  }

  delete nodes[id];
}

function addNode(action, index) {
  if (!isObj(action.node)) {
    throw new Error(`actions[${index}] addNode: "node" is required`);
  }

  const id = String(action.__assignedId);
  const exists = hasNode(id);

  if (exists && !action.overwrite) {
    throw new Error(`actions[${index}] addNode: node ${id} exists (set overwrite=true to replace)`);
  }

  nodes[id] = clone(action.node);
  ensureInputs(id);

  const connectInputs = isObj(action.connectInputs) ? action.connectInputs : {};
  for (const [inputName, src] of Object.entries(connectInputs)) {
    if (src === null) {
      delete nodes[id].inputs[inputName];
      continue;
    }

    const [fromId, out] = resolveLinkSource(src, `actions[${index}].connectInputs.${inputName}`);
    assertNodeExists(fromId, `actions[${index}] connectInputs.${inputName}`);
    nodes[id].inputs[inputName] = [fromId, out];
  }

  const connectOutputs = Array.isArray(action.connectOutputs) ? action.connectOutputs : [];
  for (const c of connectOutputs) {
    connect({
      fromNodeId: id,
      fromOutput: c.fromOutput ?? c.output ?? 0,
      toNodeId: c.toNodeId ?? c.to ?? (c.toRef ? `@${c.toRef}` : undefined),
      toInput: c.toInput ?? c.input,
    });
  }
}

// Выполняем действия по порядку
for (let i = 0; i < actions.length; i++) {
  const a = actions[i];
  if (!a.type) throw new Error(`actions[${i}].type is required`);

  if (a.type === 'addNode') addNode(a, i);
  else if (a.type === 'connect') connect(a);
  else if (a.type === 'disconnect') disconnect(a);
  else if (a.type === 'removeNode') removeNode(a);
  else throw new Error(`actions[${i}]: unknown type "${a.type}"`);
}

const updatedWorkflow = hasPromptWrapper
  ? { ...workflowRoot, prompt: nodes }
  : nodes;

return [
  {
    json: {
      workflow: updatedWorkflow,
      idMap,
    },
  },
];
